/**
 * @summary Import catalog from Excel/CSV
 */
export const getImportCatalogUrl = () => {
  return `/api/catalog/import`;
};

export const importCatalog = async (
  importCatalogBody: ImportCatalogBody,
  options?: RequestInit,
): Promise<ImportResult> => {
  const formData = new FormData();
  formData.append(`file`, importCatalogBody.file);
  if (importCatalogBody.regionId !== undefined) {
    formData.append(`regionId`, importCatalogBody.regionId.toString());
  }

  return customFetch<ImportResult>(getImportCatalogUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

